const leagues = [
  { name: 'ICC Cricket World Cup', type: 'International Championship', note: 'The biggest ODI event contested by top nations.', image: 'data:image/jpeg;base64,' },
  { name: 'ICC T20 World Cup', type: 'Fast-paced global tournament', note: 'A showcase of power-hitting and smart tactics.', image: 'data:image/jpeg;base64,' },
  { name: 'IPL', type: 'Franchise League', note: 'India’s star-studded T20 league with huge fan followings.', image: 'data:image/jpeg;base64,' },
  { name: 'Big Bash League', type: 'Australian T20 League', note: 'Known for entertainment, big hits, and young talent.', image: 'data:image/jpeg;base64,' },
  { name: 'SA20', type: 'South African T20 League', note: 'A rising league mixing international stars with local talent.', image: 'data:image/jpeg;base64,' },
  { name: 'Champions Trophy', type: 'Elite ODI Tournament', note: 'A high-stakes ODI competition featuring top-ranked teams.', image: 'data:image/jpeg;base64,' },
  { name: 'World Test Championship', type: 'Long-Form Championship', note: 'A prestigious Test series pathway to crown the best side.', image: 'data:image/jpeg;base64,' },
  { name: 'Asia Cup', type: 'Regional Championship', note: 'A thrilling ODI and T20 contest between top Asian teams.', image: 'data:image/jpeg;base64,' }, 
];

function Leagues() {
  return (
    <section className="page-card">
      <p className="eyebrow">Famous leagues and tournaments</p>
      <h1>ICC and global cricket action</h1>
      <div className="info-grid">
        {leagues.map((item) => (
          <article className="mini-card" key={item.name}>
            <img src={item.image} alt={`${item.name} cricket league`} />
            <h2>{item.name}</h2>
            <p className="tag">{item.type}</p>
            <p>{item.note}</p>
          </article>
        ))}
      </div>
    </section>
  );
}

export default Leagues;
